# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session
import bcrypt

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Mock database
users = {
    'user1': {'email': 'user1@example.com', 'password_hash': bcrypt.hashpw(b'password123', bcrypt.gensalt()), 'two_factor_enabled': False}
}

@app.route('/update_profile', methods=['POST'])
def update_profile():
    if 'username' not in session:
        return jsonify({'error': 'Unauthorized'}), 401

    username = session['username']
    data = request.get_json()

    new_email = data.get('email')
    new_password = data.get('password')
    two_factor_enabled = data.get('two_factor_enabled')

    if not new_email and not new_password and not two_factor_enabled:
        return jsonify({'error': 'No updates provided'}), 400

    if new_email:
        users[username]['email'] = new_email

    if new_password:
        password_hash = bcrypt.hashpw(new_password.encode('utf-8'), bcrypt.gensalt())
        users[username]['password_hash'] = password_hash

    if two_factor_enabled is not None:
        users[username]['two_factor_enabled'] = two_factor_enabled

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)